/**
 * Mock data for Growth · Creative Performance.
 *
 * One row per live ad creative. The page is a read surface: ROAS verified
 * against orders (not what the platform claims), POAS after product cost,
 * frequency + CTR for fatigue, a 7-day trajectory mini-bar, and a verdict.
 */

export type CreativeVerdict = "scale" | "healthy" | "watch" | "refresh" | "cut";
export type CreativeFormat = "video" | "image" | "carousel";
export type CreativeFreqState = "ok" | "warn" | "hot";

export interface CreativeRow {
  /** Stable id for keys + Bridge action context. */
  id: string;
  name: string;
  /** e.g. "Meta · Video · 18d live" */
  sub: string;
  platform: "Meta" | "TikTok" | "Google";
  format: CreativeFormat;
  /** CSS gradient used as the thumbnail's faux still. */
  thumbBg: string;
  spend: string;
  spendNum: number;
  /** Verified vs reported ROAS — both shown so the gap is honest. */
  roas: string;
  roasReported: string;
  /** POAS (profit on ad spend) — after product cost. */
  poas: string;
  poasPolar: "pos" | "neg" | "flat";
  poasLbl: string;
  freq: string;
  freqState: CreativeFreqState;
  ctr: string;
  ctrDir: "up" | "down" | "flat";
  /** 7 normalized heights (0-100) for the mini bar trend. */
  trend: number[];
  verdict: CreativeVerdict;
}

