"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  CREATIVE_ROWS,
  VERDICT_LABEL,
  creativeMetrics,
  creativeAI,
  type CreativeRow,
} from "@/features/growth/api/growth-creative-data";
import "./creative.css";

type SortKey = "name" | "spend" | "roas" | "poas" | "freq";

const PERIOD_LABELS = ["Last 7 days", "Last 30 days", "Last 90 days"];

const formatIcon = (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <rect x="3" y="5" width="18" height="14" rx="2" />
    <circle cx="8.5" cy="10" r="1.6" fill="currentColor" stroke="none" />
    <path d="M21 15l-5-4-9 8" />
  </svg>
);
const carouselIcon = (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <rect x="7" y="5" width="10" height="14" rx="1.5" />
    <line x1="4" y1="8" x2="4" y2="16" />
    <line x1="20" y1="8" x2="20" y2="16" />
  </svg>
);
const playIcon = (
  <svg viewBox="0 0 16 16">
    <path d="M4 3 L13 8 L4 13 Z" />
  </svg>
);
const arrowIcon = (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="5" y1="12" x2="19" y2="12" />
    <polyline points="12 5 19 12 12 19" />
  </svg>
);

const num = (s: string) => {
  if (!s) return 0;
  const m = s.replace(/[,$]/g, "").match(/-?\d+(?:\.\d+)?/);
  if (!m) return 0;
  let v = parseFloat(m[0]);
  if (/k/i.test(s)) v *= 1000;
  if (/m/i.test(s)) v *= 1_000_000;
  return v;
};

export default function CreativePage() {
  const [periodIdx, setPeriodIdx] = useState(1);
  const [sortKey, setSortKey] = useState<SortKey>("spend");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);
  const { openBridge } = useBridge();

  const rows = useMemo(() => {
    const arr = [...CREATIVE_ROWS];
    arr.sort((a, b) => {
      if (sortKey === "name") return sortDir * a.name.localeCompare(b.name);
      if (sortKey === "spend") return sortDir * (a.spendNum - b.spendNum);
      if (sortKey === "roas") return sortDir * (num(a.roas) - num(b.roas));
      if (sortKey === "poas") return sortDir * (num(a.poas) - num(b.poas));
      if (sortKey === "freq") return sortDir * (num(a.freq) - num(b.freq));
      return 0;
    });
    return arr;
  }, [sortKey, sortDir]);

  const onSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "name" ? 1 : -1);
    }
  };

  const th = (k: SortKey, label: React.ReactNode, num = false) => {
    const active = sortKey === k;
    return (
      <th
        className={`${num ? "num " : ""}${active ? "active" : ""}`}
        onClick={() => onSort(k)}
      >
        {label}
        <span className="sort-ar">{active && sortDir < 0 ? "↓" : "↑"}</span>
      </th>
    );
  };

  return (
    <div className="growth-creative-page">
      <DeptHeader
        dept="growth"
        title="Creative Performance"
        meta={
          <>
            <span className="live">Live</span> · Verified return, profit &amp; fatigue per ad creative · matched to your orders
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <button className="btn-util">New creative in Study →</button>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} accent="var(--d-growth)" />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Creative spend</div>
          <div className="metric-v">{creativeMetrics.spend}</div>
          <div className="metric-s">{creativeMetrics.spendSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Verified ROAS</div>
          <div className="metric-v green">{creativeMetrics.verifiedRoas}</div>
          <div className="metric-s">{creativeMetrics.reportedRoas}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Avg POAS</div>
          <div className="metric-v green">{creativeMetrics.poas}</div>
          <div className="metric-s">{creativeMetrics.poasSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Fatiguing</div>
          <div className="metric-v amber">{creativeMetrics.fatiguing}</div>
          <div className="metric-s">{creativeMetrics.fatiguingSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Spend at risk</div>
          <div className="metric-v red">{creativeMetrics.spendAtRisk}</div>
          <div className="metric-s">{creativeMetrics.spendAtRiskSub}</div>
        </div>
      </div>

      <AIStrip label={creativeAI.label} meta={creativeAI.meta} cards={creativeAI.cards} />

      <SectionLabel>Every creative, ranked by spend — verified return, profit and fatigue</SectionLabel>
      <div className="cr-table-wrap">
        <table className="cr-table">
          <thead>
            <tr>
              {th("name", "Creative")}
              {th("spend", "Spend", true)}
              {th("roas", "Verified ROAS", true)}
              {th("poas", "POAS", true)}
              {th("freq", "Freq · CTR", true)}
              <th data-nosort>Trajectory</th>
              <th className="num" data-nosort>Verdict</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((c) => (
              <CreativeRowEl key={c.id} c={c} openBridge={openBridge} />
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

interface RowProps {
  c: CreativeRow;
  openBridge: ReturnType<typeof useBridge>["openBridge"];
}

function CreativeRowEl({ c, openBridge }: RowProps) {
  return (
    <tr className={`cr-row v-${c.verdict}`}>
      <td>
        <div className="cr-cell">
          <span className="cr-thumb" style={{ background: c.thumbBg }}>
            {c.format === "video" ? (
              <span className="play">{playIcon}</span>
            ) : (
              <span className="fmt">{c.format === "carousel" ? carouselIcon : formatIcon}</span>
            )}
          </span>
          <div>
            <div className="cr-name">{c.name}</div>
            <div className="cr-sub">{c.sub}</div>
          </div>
        </div>
      </td>
      <td className="num">
        <span className="cr-spend">{c.spend}</span>
      </td>
      <td className="num">
        <div className="cr-roas">
          <div className="v">{c.roas}</div>
          <div className="rep">rep <s>{c.roasReported}</s></div>
        </div>
      </td>
      <td className="num">
        <div className={`cr-poas ${c.poasPolar}`}>
          <div className="v">{c.poas}</div>
          <div className="lbl">{c.poasLbl}</div>
        </div>
      </td>
      <td className="num">
        <div className={`cr-freq ${c.freqState === "ok" ? "" : c.freqState}`}>
          <div className="v">{c.freq}</div>
          <div className="ctr">
            CTR {c.ctr}{" "}
            <span className={c.ctrDir}>
              {c.ctrDir === "up" ? "↑" : c.ctrDir === "down" ? "↓" : "→"}
            </span>
          </div>
        </div>
      </td>
      <td>
        <div className="cr-trend">
          {c.trend.map((h, i) => (
            <span key={i} className="bar" style={{ height: `${h}%` }} />
          ))}
        </div>
      </td>
      <td className="num cr-action-cell">
        <span className={`cr-verdict ${c.verdict}`}>{VERDICT_LABEL[c.verdict]}</span>
        <button
          className="cr-bridge"
          type="button"
          onClick={() => openBridge("growth")}
        >
          {arrowIcon}
          Bridge
        </button>
      </td>
    </tr>
  );
}
